from typing import Optional

class LoginScreen:
    def __init__(self, profile: 'Profile'):
        self.profile = profile
        self.display_message = ""

    def display(self, message: str):
        self.display_message = message
        print(message)

    def update_profile(self, new_profile: 'Profile'):
        self.profile = new_profile

class Profile:
    def __init__(self, name: str):
        self.name = name

def main():
    profile = Profile("user1")
    login_screen = LoginScreen(profile)
    login_screen.display("Welcome to the login screen!")
    login_screen.update_profile(Profile("user2"))
    login_screen.display(f"Switched to {login_screen.profile.name}")

if __name__ == "__main__":
    main()
